/// Write to connection (TLS or plain).
/// TigerStyle: Runtime dispatch based on TLS availability.
fn connectionWrite(
    maybe_tls: ?*const TLSStream,
    io: *Io,
    stream: Io.net.Stream,
    data: []const u8,
) !void {
    _ = io;
    assert(data.len > 0); // S1: precondition

    if (maybe_tls) |tls| {
        // TLS write (blocking - std.Io handles socket-level async)
        var mutable_tls = tls.*;
        _ = try mutable_tls.write(data);
    } else {
        // Plain non-blocking socket write. O_NONBLOCK is set by setConnectionNonBlocking.
        // Cannot use std.Io stream.writer here: netWritePosix treats EAGAIN as a
        // programmer bug because it expects blocking sockets.
        // On EAGAIN: return SendBufferFull so the caller can handle backpressure.
        var written: usize = 0;
        while (written < data.len) {
            const remaining = data[written..];
            const rc = std.posix.system.write(stream.socket.handle, remaining.ptr, remaining.len);
            switch (std.posix.errno(rc)) {
                .SUCCESS => written += @intCast(rc),
                .INTR => {},
                .AGAIN => return error.SendBufferFull,
                .CONNRESET => return error.ConnectionResetByPeer,
                .PIPE => return error.BrokenPipe,
                else => return error.Unexpected,
            }
        }
    }
}

