     1→// serval-socket/socket.zig
     2→//! Unified Socket Abstraction
     3→//!
     4→//! Tagged union providing a consistent interface for both plain TCP and TLS sockets.
     5→//! TigerStyle: Explicit types, no generics, runtime dispatch is acceptable (P1: network >> CPU).
     6→
     7→const std = @import("std");
     8→const assert = std.debug.assert;
     9→const posix = std.posix;
    10→const serval_core = @import("serval-core");
    11→const closeFd = serval_core.closeFd;
    12→
    13→pub const tls_socket = @import("tls_socket.zig");
    14→
    15→// =============================================================================
    16→// Error Types
    17→// =============================================================================
    18→
    19→/// Unified error type for socket operations.
    20→/// TigerStyle: Explicit error set, no catch {}.
    21→pub const SocketError = error{
    22→    /// Connection was reset by peer (RST received).
    23→    ConnectionReset,
    24→    /// Connection was closed cleanly by peer.
    25→    ConnectionClosed,
    26→    /// Write to closed connection (SIGPIPE/EPIPE).
    27→    BrokenPipe,
    28→    /// Operation timed out.
    29→    Timeout,
    30→    /// TLS-specific error (handshake, encryption, certificate).
    31→    TLSError,
    32→    /// Unexpected error from underlying syscall or SSL.
    33→    Unexpected,
    34→};
    35→
    36→// =============================================================================
    37→// Plain Socket
    38→// =============================================================================
    39→
    40→/// Plain TCP socket (no encryption).
    41→/// TigerStyle: Thin wrapper over fd with explicit lifecycle.
    42→pub const PlainSocket = struct {
    43→    fd: i32,
    44→
    45→    /// Read data into buffer.
    46→    /// Returns bytes read, 0 on EOF/clean close.
    47→    /// TigerStyle S1: Assertions for preconditions.
    48→    /// TigerStyle S2: Explicit u32 return type.
    49→    pub fn read(self: *PlainSocket, buf: []u8) SocketError!u32 {
    50→        assert(self.fd >= 0); // S1: precondition
    51→        assert(buf.len > 0); // S1: precondition
    52→        assert(buf.len <= std.math.maxInt(u32)); // S2: buffer fits in u32
    53→
    54→        const n = posix.read(self.fd, buf) catch |err| {
    55→            return map_posix_error(err);
    56→        };
    57→
    58→        // S2: explicit cast with bounds check
    59→        assert(n <= std.math.maxInt(u32));
    60→        return @intCast(n);
    61→    }
    62→
    63→    /// Write data to socket.
    64→    /// Returns bytes written.
    65→    /// TigerStyle S1: Assertions for preconditions.
    66→    /// TigerStyle S2: Explicit u32 return type.
    67→    pub fn write(self: *PlainSocket, data: []const u8) SocketError!u32 {
    68→        assert(self.fd >= 0); // S1: precondition
    69→        assert(data.len > 0); // S1: precondition
    70→        assert(data.len <= std.math.maxInt(u32)); // S2: data fits in u32
    71→
    72→        const n = posixSendCompat(self.fd, data) catch |err| {
    73→            return map_posix_error(err);
    74→        };
    75→
    76→        // S2: explicit cast with bounds check
    77→        assert(n <= std.math.maxInt(u32));
    78→        return @intCast(n);
    79→    }
    80→
    81→    /// Close the socket.
    82→    /// TigerStyle: Explicit close, caller owns fd.
    83→    pub fn close(self: *PlainSocket) void {
    84→        assert(self.fd >= 0); // S1: precondition
    85→        closeFd(self.fd);
    86→        self.fd = -1; // Mark as closed
    87→    }
    88→};
    89→
    90→// =============================================================================
    91→// Socket Union
    92→// =============================================================================
    93→
    94→/// Unified socket type for both plain and TLS connections.
    95→/// TigerStyle: Tagged union, explicit dispatch, no generics.
    96→pub const Socket = union(enum) {
    97→    plain: PlainSocket,
    98→    tls: tls_socket.TLSSocket,
    99→
   100→    /// Plain socket creation namespace.
   101→    pub const Plain = struct {
   102→        /// Create plain client socket from fd.
   103→        /// TigerStyle: Consistent API with TLS.init_client.
   104→        pub fn init_client(fd: i32) Socket {
   105→            assert(fd >= 0); // S1: precondition
   106→            return .{ .plain = .{ .fd = fd } };
   107→        }
   108→
   109→        /// Create plain server socket from fd.
   110→        /// Same as init_client for plain TCP, but documents intent.
   111→        /// TigerStyle: Symmetric API with TLS.init_server.
   112→        pub fn init_server(fd: i32) Socket {
   113→            assert(fd >= 0); // S1: precondition
   114→            return .{ .plain = .{ .fd = fd } };
   115→        }
   116→    };
   117→
   118→    /// TLS socket creation namespace.
   119→    /// Delegates to tls_socket module.
   120→    pub const TLS = tls_socket;
   121→
   122→    /// Read data into buffer.
   123→    /// Returns bytes read, 0 on EOF/clean close.
   124→    /// TigerStyle: Dispatch to underlying implementation.
   125→    /// TigerStyle S2: Explicit u32 return type.
   126→    pub fn read(self: *Socket, buf: []u8) SocketError!u32 {
   127→        assert(buf.len > 0); // S1: precondition
   128→
   129→        return switch (self.*) {
   130→            .plain => |*s| s.read(buf),
   131→            .tls => |*s| s.read(buf),
   132→        };
   133→    }
   134→
   135→    /// Write data to socket.
   136→    /// Returns bytes written.
   137→    /// TigerStyle: Dispatch to underlying implementation.
   138→    /// TigerStyle S2: Explicit u32 return type.
   139→    pub fn write(self: *Socket, data: []const u8) SocketError!u32 {
   140→        assert(data.len > 0); // S1: precondition
   141→
   142→        return switch (self.*) {
   143→            .plain => |*s| s.write(data),
   144→            .tls => |*s| s.write(data),
   145→        };
   146→    }
   147→
   148→    /// Close the socket and free resources.
   149→    /// TigerStyle: Single close path for both types.
   150→    pub fn close(self: *Socket) void {
   151→        const fd = self.get_fd();
   152→        assert(fd >= 0);
   153→        switch (self.*) {
   154→            .plain => |*s| s.close(),
   155→            .tls => |*s| s.close(),
   156→        }
   157→    }
   158→
   159→    /// Get raw file descriptor.
   160→    /// Useful for splice (plaintext only) and poll operations.
   161→    /// TigerStyle: Zero-copy splice needs raw fd.
   162→    pub fn get_fd(self: Socket) i32 {
   163→        const fd = switch (self) {
   164→            .plain => |s| s.fd,
   165→            .tls => |s| s.fd,
   166→        };
   167→        assert(fd >= -1);
   168→        return fd;
   169→    }
   170→
   171→    /// Check if this is a TLS socket.
   172→    /// Useful for determining splice eligibility.
   173→    /// TigerStyle: Explicit type check, no instanceof pattern.
   174→    pub fn is_tls(self: Socket) bool {
   175→        const fd = self.get_fd();
   176→        assert(fd >= -1);
   177→        return switch (self) {
   178→            .plain => false,
   179→            .tls => true,
   180→        };
   181→    }
   182→
   183→    /// Returns true if this socket can use splice() for zero-copy I/O.
   184→    /// Plain sockets always support splice. TLS sockets only support splice
   185→    /// when kTLS kernel offload is enabled (kernel handles encryption).
   186→    ///
   187→    /// Why this matters: splice() moves data between file descriptors without
   188→    /// copying through userspace. With plain TCP, the kernel handles all I/O.
   189→    /// With userspace TLS, data must pass through OpenSSL for encryption,
   190→    /// making splice() impossible. kTLS moves TLS encryption into the kernel,
   191→    /// re-enabling splice() for encrypted connections.
   192→    ///
   193→    /// TigerStyle: Explicit switch on socket type (no default case).
   194→    pub fn can_splice(self: *const Socket) bool {
   195→        const fd = self.get_fd();
   196→        assert(fd >= -1);
   197→        return switch (self.*) {
   198→            .plain => true, // Plain TCP: kernel handles I/O, splice always works
   199→            .tls => |*s| s.stream.isKtls(), // TLS: only splice if kTLS enabled
   200→        };
   201→    }
   202→
   203→    /// Check if this socket is using kTLS kernel offload.
   204→    /// Always returns false for plain sockets.
   205→    /// For TLS sockets, returns true if kTLS is enabled.
   206→    /// TigerStyle: Explicit switch on socket type (no default case).
   207→    pub fn is_ktls(self: *const Socket) bool {
   208→        const fd = self.get_fd();
   209→        assert(fd >= -1);
   210→        return switch (self.*) {
   211→            .plain => false, // Plain TCP: not TLS, so not kTLS
   212→            .tls => |*s| s.stream.isKtls(), // TLS: check if kTLS mode
   213→        };
   214→    }
   215→
   216→    /// Returns true if a TLS socket has decrypted bytes buffered internally.
   217→    /// Plain sockets always return false because the kernel poll state fully
   218→    /// represents read availability.
   219→    pub fn has_pending_read(self: *const Socket) bool {
   220→        const fd = self.get_fd();
   221→        assert(fd >= -1);
   222→        return switch (self.*) {
   223→            .plain => false,
   224→            .tls => |*s| s.has_pending_read(),
   225→        };
   226→    }
   227→
   228→    // =========================================================================
   229→    // Bulk Transfer Operations
   230→    // =========================================================================
   231→
   232→    /// Maximum iterations for write_all to prevent infinite loops.
   233→    /// 1024 partial writes is far beyond any legitimate scenario.
   234→    /// TigerStyle S3: Bounded loops with explicit max iterations.
   235→    pub const max_write_iterations_count: u32 = 1024;
   236→
   237→    /// Maximum iterations for read_at_least to prevent infinite loops.
   238→    /// TigerStyle S3: Bounded loops with explicit max iterations.
   239→    pub const max_read_iterations_count: u32 = 1024;
   240→
   241→    /// Write all bytes to socket, handling partial writes.
   242→    /// Returns error if unable to write all bytes within bounded iterations.
   243→    /// TigerStyle: Bounded retry loop, explicit assertions.
   244→    pub fn write_all(self: *Socket, data: []const u8) SocketError!void {
   245→        // S1: Preconditions
   246→        assert(data.len > 0); // Empty writes are programmer error
   247→        assert(data.len <= std.math.maxInt(u32));
   248→
   249→        const data_len: u32 = @intCast(data.len);
   250→        var sent: u32 = 0;
   251→        var iterations: u32 = 0;
   252→
   253→        // S3: Bounded loop with explicit maximum
   254→        while (sent < data_len and iterations < max_write_iterations_count) : (iterations += 1) {
   255→            const offset: usize = @intCast(sent);
   256→            const n: u32 = try self.write(data[offset..]);
   257→
   258→            // Zero write means peer closed or unrecoverable error
   259→            if (n == 0) return SocketError.ConnectionClosed;
   260→
   261→            assert(n <= data_len);
   262→            sent += n;
   263→            assert(sent <= data_len);
   264→        }
   265→
   266→        // Check if loop exited due to iteration limit
   267→        if (sent < data_len) return SocketError.Unexpected;
   268→
   269→        // S2: Postcondition - all bytes written
   270→        assert(sent == data_len);
   271→    }
   272→
   273→    /// Read at least min_bytes into buffer.
   274→    /// Returns total bytes read (may be more than min_bytes, up to buffer.len).
   275→    /// Returns error if unable to read minimum bytes within bounded iterations.
   276→    /// TigerStyle: Bounded retry loop, explicit assertions.
   277→    pub fn read_at_least(self: *Socket, buffer: []u8, min_bytes: u32) SocketError!u32 {
   278→        // S1: Preconditions
   279→        assert(buffer.len > 0); // Empty buffer is programmer error
   280→        assert(buffer.len <= std.math.maxInt(u32));
   281→        assert(min_bytes > 0); // Zero min_bytes is programmer error
   282→
   283→        const buffer_len: u32 = @intCast(buffer.len);
   284→        assert(min_bytes <= buffer_len); // min_bytes cannot exceed buffer capacity
   285→
   286→        var total_bytes: u32 = 0;
   287→        var iterations: u32 = 0;
   288→
   289→        // S3: Bounded loop with explicit maximum
   290→        while (total_bytes < min_bytes and iterations < max_read_iterations_count) : (iterations += 1) {
   291→            const offset: usize = @intCast(total_bytes);
   292→            const n: u32 = try self.read(buffer[offset..]);
   293→
   294→            // Zero read means EOF before min_bytes reached
   295→            if (n == 0) return SocketError.ConnectionClosed;
   296→
   297→            assert(n <= buffer_len);
   298→            total_bytes += n;
   299→            assert(total_bytes <= buffer_len);
   300→        }
   301→
   302→        // Check if loop exited due to iteration limit
   303→        if (total_bytes < min_bytes) return SocketError.Unexpected;
   304→
   305→        // S2: Postcondition - read at least min_bytes
   306→        assert(total_bytes >= min_bytes);
   307→        assert(total_bytes <= buffer_len);
   308→        return total_bytes;
   309→    }
   310→};
   311→
   312→// =============================================================================
   313→// Error Mapping
   314→// =============================================================================
   315→
   316→fn posixSendCompat(fd: i32, data: []const u8) anyerror!usize {
   317→    assert(fd >= 0);
   318→    assert(data.len > 0);
   319→
   320→    if (@hasDecl(posix, "send")) {
   321→        return posix.send(fd, data, 0);
   322→    }
   323→
   324→    while (true) {
   325→        const rc = std.c.send(fd, data.ptr, data.len, 0);
   326→        switch (std.c.errno(rc)) {
   327→            .SUCCESS => return @intCast(rc),
   328→            .INTR => continue,
   329→            .AGAIN => return error.WouldBlock,
   330→            .PIPE => return error.BrokenPipe,
   331→            .CONNRESET => return error.ConnectionResetByPeer,
   332→            .TIMEDOUT => return error.ConnectionTimedOut,
   333→            else => return error.Unexpected,
   334→        }
   335→    }
   336→}
   337→
   338→/// Map posix errors to SocketError.
   339→/// TigerStyle S6: Explicit error handling, no catch {}.
   340→fn map_posix_error(err: anyerror) SocketError {
   341→    assert(@errorName(err).len > 0);
   342→    return switch (err) {
   343→        error.ConnectionResetByPeer => SocketError.ConnectionReset,
   344→        error.BrokenPipe => SocketError.BrokenPipe,
   345→        error.ConnectionTimedOut => SocketError.Timeout,
   346→        error.WouldBlock => SocketError.Timeout,
   347→        else => SocketError.Unexpected,
   348→    };
   349→}
   350→
   351→// =============================================================================
   352→// Tests
   353→// =============================================================================
   354→
   355→fn testSocket(domain: u32, sock_type: u32, protocol: u32) !posix.socket_t {
   356→    while (true) {
   357→        const rc = std.c.socket(@intCast(domain), @intCast(sock_type), @intCast(protocol));
   358→        switch (std.c.errno(rc)) {
   359→            .SUCCESS => return @intCast(rc),
   360→            .INTR => continue,
   361→            else => return error.SocketFailed,
   362→        }
   363→    }
   364→}
   365→
   366→fn testSocketPair(domain: u32, sock_type: u32, protocol: u32) ![2]posix.socket_t {
   367→    var fds: [2]posix.socket_t = undefined;
   368→
   369→    while (true) {
   370→        const rc = std.c.socketpair(@intCast(domain), @intCast(sock_type), @intCast(protocol), &fds);
   371→        switch (std.c.errno(rc)) {
   372→            .SUCCESS => return fds,
   373→            .INTR => continue,
   374→            else => return error.SocketFailed,
   375→        }
   376→    }
   377→}
   378→
   379→test "Socket.Plain.init_client creates plain socket" {
   380→    // Verify init_client returns a non-TLS socket with correct fd.
   381→    const fd = try testSocket(posix.AF.INET, posix.SOCK.STREAM, 0);
   382→    defer posix.close(fd);
   383→
   384→    var sock = Socket.Plain.init_client(fd);
   385→    try std.testing.expect(!sock.is_tls());
   386→    try std.testing.expectEqual(fd, sock.get_fd());
   387→}
   388→
   389→test "Socket.Plain.init_server creates plain socket" {
   390→    const fd = try testSocket(posix.AF.INET, posix.SOCK.STREAM, 0);
   391→    defer posix.close(fd);
   392→
   393→    var sock = Socket.Plain.init_server(fd);
   394→    try std.testing.expect(!sock.is_tls());
   395→    try std.testing.expectEqual(fd, sock.get_fd());
   396→}
   397→
   398→test "Socket.is_tls returns correct value" {
   399→    const fd = try testSocket(posix.AF.INET, posix.SOCK.STREAM, 0);
   400→    defer posix.close(fd);
   401→
   402→    const plain_sock = Socket.Plain.init_client(fd);
   403→    try std.testing.expect(!plain_sock.is_tls());
   404→}
   405→
   406→test "Socket.get_fd returns underlying fd" {
   407→    const fd = try testSocket(posix.AF.INET, posix.SOCK.STREAM, 0);
   408→    defer posix.close(fd);
   409→
   410→    const sock = Socket.Plain.init_client(fd);
   411→    try std.testing.expectEqual(fd, sock.get_fd());
   412→}
   413→
   414→test "map_posix_error maps common errors" {
   415→    try std.testing.expectEqual(SocketError.ConnectionReset, map_posix_error(error.ConnectionResetByPeer));
   416→    try std.testing.expectEqual(SocketError.BrokenPipe, map_posix_error(error.BrokenPipe));
   417→    try std.testing.expectEqual(SocketError.Timeout, map_posix_error(error.ConnectionTimedOut));
   418→    try std.testing.expectEqual(SocketError.Timeout, map_posix_error(error.WouldBlock));
   419→    try std.testing.expectEqual(SocketError.Unexpected, map_posix_error(error.OutOfMemory));
   420→}
