   422→test "PlainSocket read/write require valid fd" {
   423→    // Create socket pair for testing read/write
   424→    const fds = try testSocketPair(posix.AF.UNIX, posix.SOCK.STREAM, 0);
   425→    defer posix.close(fds[0]);
   426→    defer posix.close(fds[1]);
