   460→
   461→test "Socket.can_splice returns true for plain sockets" {
   462→    const fd = try testSocket(posix.AF.INET, posix.SOCK.STREAM, 0);
   463→    defer posix.close(fd);
   464→
   465→    const sock = Socket.Plain.init_client(fd);
   466→    // Plain sockets always support splice (kernel handles I/O)
