   471→    const fd = try testSocket(posix.AF.INET, posix.SOCK.STREAM, 0);
   472→    defer posix.close(fd);
   473→
   474→    const sock = Socket.Plain.init_client(fd);
   475→    // Plain sockets are not TLS, so cannot be kTLS
   476→    try std.testing.expect(!sock.is_ktls());
