   478→
   479→// =============================================================================
   480→// Bulk Transfer Operation Tests
   481→// =============================================================================
   482→
   483→test "Socket.write_all sends all bytes" {
   484→    const fds = try testSocketPair(posix.AF.UNIX, posix.SOCK.STREAM, 0);
   485→    defer posix.close(fds[0]);
   486→    defer posix.close(fds[1]);
   487→
   488→    var sock = Socket.Plain.init_client(fds[0]);
   489→
   490→    // Write all bytes via write_all
   491→    const msg = "hello world test message";
   492→    try sock.write_all(msg);
