     1→// lib/serval-proxy/connect.zig
     2→//! Connection Management
     3→//!
     4→//! Thin wrapper around serval-client for upstream connections.
     5→//! Provides proxy-specific ConnectResult type for observability.
     6→//!
     7→//! TigerStyle: Delegates to serval-client, adds proxy-specific fields.
     8→
     9→const std = @import("std");
    10→const assert = std.debug.assert;
    11→const posix = std.posix;
    12→const Io = std.Io;
    13→
    14→const serval_core = @import("serval-core");
    15→const debugLog = serval_core.debugLog;
    16→const time = serval_core.time;
    17→
    18→const serval_net = @import("serval-net");
    19→const DnsResolver = serval_net.DnsResolver;
    20→
    21→const serval_socket = @import("serval-socket");
    22→const Socket = serval_socket.Socket;
    23→
    24→const serval_client = @import("serval-client");
    25→const Client = serval_client.Client;
    26→const ClientError = serval_client.ClientError;
    27→
    28→const types = @import("types.zig");
    29→const ForwardError = types.ForwardError;
    30→const Protocol = types.Protocol;
    31→
    32→const Upstream = serval_core.types.Upstream;
    33→
    34→const serval_tls = @import("serval-tls");
    35→const ssl = serval_tls.ssl;
    36→
    37→// =============================================================================
    38→// Configuration
    39→// =============================================================================
    40→
    41→/// Configuration for upstream connection.
    42→/// TigerStyle: Explicit config struct, no hidden defaults.
    43→pub const ConnectConfig = struct {
    44→    /// Connection timeout in nanoseconds.
    45→    /// TigerStyle: u64 for nanoseconds, explicit unit in name.
    46→    timeout_ns: u64,
    47→    /// Whether to verify upstream TLS certificates.
    48→    /// TigerStyle: Explicit, not inferred from environment.
    49→    verify_upstream_tls: bool,
    50→    /// Optional SSL context for TLS connections.
    51→    /// Caller provides this for TLS; null means no TLS capability.
    52→    /// TigerStyle: Caller owns context lifecycle.
    53→    client_ctx: ?*ssl.SSL_CTX = null,
    54→};
    55→
    56→// =============================================================================
    57→// Connection Result
    58→// =============================================================================
    59→
    60→/// Result of connecting to upstream, includes timing and socket info.
    61→/// TigerStyle: Wraps serval-client result with proxy-specific fields.
    62→pub const ConnectResult = struct {
    63→    /// Unified socket abstraction (plain or TLS).
    64→    /// TigerStyle: Single type for both, caller uses read/write interface.
    65→    socket: Socket,
    66→    /// Timestamp when connection was established (monotonic nanoseconds).
    67→    /// TigerStyle: u64 for nanoseconds, explicit unit in name.
    68→    created_ns: u64,
    69→    /// Protocol negotiated at connection time. Immutable for connection lifetime.
    70→    /// TigerStyle: Single source of truth, no mid-connection renegotiation.
    71→    /// Future: TLS negotiation via ALPN, h2c detection via preface.
    72→    protocol: Protocol,
    73→    /// Duration of DNS resolution in nanoseconds (0 if IP address was used).
    74→    /// TigerStyle: u64 for nanoseconds, explicit unit in name.
    75→    dns_duration_ns: u64,
    76→    /// Duration of TCP connect in nanoseconds.
    77→    tcp_connect_duration_ns: u64,
    78→    /// Duration of TLS handshake in nanoseconds (0 if plaintext).
    79→    tls_handshake_duration_ns: u64,
    80→    /// Local port of the connection.
    81→    local_port: u16,
    82→};
    83→
    84→// =============================================================================
    85→// Port Extraction
    86→// =============================================================================
    87→
    88→/// Get local port from connected socket.
    89→/// Returns 0 if unable to retrieve (non-fatal).
    90→pub fn getLocalPort(fd: i32) u16 {
    91→    assert(fd >= 0);
    92→
    93→    var addr: posix.sockaddr.in = std.mem.zeroes(posix.sockaddr.in);
    94→    var addr_len: posix.socklen_t = @sizeOf(posix.sockaddr.in);
    95→
    96→    if (std.c.getsockname(fd, @ptrCast(&addr), &addr_len) != 0) {
    97→        return 0;
    98→    }
    99→
   100→    return std.mem.bigToNative(u16, addr.port);
   101→}
   102→
   103→/// Get local port from Socket abstraction.
   104→/// TigerStyle: Works with both plain and TLS sockets.
   105→pub fn getLocalPortFromSocket(socket: Socket) u16 {
   106→    return getLocalPort(socket.get_fd());
   107→}
   108→
   109→// =============================================================================
   110→// TCP Connect
   111→// =============================================================================
   112→
   113→/// Connect to upstream using serval-client.
   114→/// TigerStyle: Delegates to serval-client, maps errors to ForwardError.
   115→pub fn connectUpstream(
   116→    upstream: *const Upstream,
