    55→    TlsHandshakeFailed,
    56→
    57→    // Send errors (from request module)
    58→    /// Send operation failed (socket error, connection reset).
    59→    SendFailed,
    60→    /// Send operation timed out.
    61→    SendTimeout,
    62→    /// Request headers exceeded buffer size.
    63→    BufferTooSmall,
    64→
    65→    // Receive errors (from response module)
    66→    /// Receive operation failed (socket error).
    67→    RecvFailed,
    68→    /// Receive operation timed out.
    69→    RecvTimeout,
    70→    /// Response headers exceeded buffer size.
    71→    ResponseHeadersTooLarge,
    72→    /// Invalid HTTP status line.
    73→    InvalidResponseStatus,
    74→    /// Invalid HTTP response headers.
    75→    InvalidResponseHeaders,
    76→    /// Connection closed by peer before response complete.
    77→    ConnectionClosed,
    78→};
    79→
    80→// =============================================================================
    81→// Result Types
    82→// =============================================================================
    83→
    84→/// Result of connecting to an upstream server.
    85→/// Includes timing information for observability.
    86→/// TigerStyle: Explicit struct with timing fields.
    87→pub const ConnectResult = struct {
    88→    /// Connection to upstream (caller must release to pool or close).
    89→    conn: Connection,
    90→    /// Duration of DNS resolution in nanoseconds (0 if cached or IP address).
    91→    dns_duration_ns: u64,
    92→    /// Duration of TCP connect in nanoseconds.
    93→    tcp_connect_duration_ns: u64,
    94→    /// Duration of TLS handshake in nanoseconds (0 if plaintext).
    95→    tls_handshake_duration_ns: u64,
    96→    /// Local port of the connection.
    97→    local_port: u16,
    98→};
    99→
   100→/// Result of a complete HTTP request (connect + send + read headers).
   101→/// TigerStyle: Explicit struct with owned connection.
   102→pub const RequestResult = struct {
   103→    /// Connection to upstream (caller must release to pool or close).
   104→    conn: Connection,
   105→    /// Parsed response headers.
   106→    response: ResponseHeaders,
   107→};
   108→
   109→// =============================================================================
   110→// Client
   111→// =============================================================================
   112→
   113→/// HTTP/1.1 client for upstream connections.
   114→/// TigerStyle: Fixed configuration, no runtime allocation.
   115→pub const Client = struct {
   116→    /// Allocator for potential future use (currently unused).
   117→    allocator: std.mem.Allocator,
   118→
   119→    /// DNS resolver for hostname lookups.
   120→    dns_resolver: *DnsResolver,
   121→
   122→    /// TLS context for client connections (null = plaintext only).
   123→    /// TigerStyle: Optional TLS support, explicit null for plaintext.
   124→    client_ctx: ?*ssl.SSL_CTX,
   125→
   126→    /// Whether to verify upstream TLS certificates.
   127→    /// TigerStyle: Explicit boolean, no implicit behavior.
   128→    verify_tls: bool,
   129→
   130→    /// Whether to enable kernel TLS offload for connections.
   131→    /// Default true for performance. Set false if kTLS causes EBADMSG errors
   132→    /// with specific servers (e.g., K8s API).
   133→    enable_ktls: bool,
   134→
   135→    /// Initialize a new HTTP client with kTLS enabled (default).
   136→    /// TigerStyle S1: Assertions for preconditions.
   137→    pub fn init(
   138→        allocator: std.mem.Allocator,
   139→        dns_resolver: *DnsResolver,
   140→        client_ctx: ?*ssl.SSL_CTX,
   141→        verify_tls: bool,
   142→    ) Client {
   143→        return initWithOptions(allocator, dns_resolver, client_ctx, verify_tls, true);
   144→    }
   145→
   146→    /// Initialize a new HTTP client with explicit kTLS control.
   147→    /// TigerStyle S1: Assertions for preconditions.
   148→    pub fn initWithOptions(
   149→        allocator: std.mem.Allocator,
   150→        dns_resolver: *DnsResolver,
   151→        client_ctx: ?*ssl.SSL_CTX,
   152→        verify_tls: bool,
   153→        enable_ktls: bool,
   154→    ) Client {
   155→        // S1: precondition - dns_resolver must be valid
   156→        assert(@intFromPtr(dns_resolver) != 0);
   157→        // S1: precondition - if verify_tls is true, client_ctx should be set (advisory)
   158→        // Note: We don't assert this because plaintext-only clients may have verify_tls=true
   159→        // as a default, and client_ctx=null means TLS upstreams will fail explicitly.
   160→
   161→        return .{
   162→            .allocator = allocator,
   163→            .dns_resolver = dns_resolver,
   164→            .client_ctx = client_ctx,
   165→            .verify_tls = verify_tls,
   166→            .enable_ktls = enable_ktls,
   167→        };
   168→    }
   169→
   170→    /// Deinitialize the client.
   171→    /// Currently a no-op since we don't own the dns_resolver or client_ctx.
   172→    /// TigerStyle: Explicit cleanup path, even if empty.
   173→    pub fn deinit(self: *Client) void {
   174→        // We don't own dns_resolver or client_ctx, so nothing to clean up
   175→        _ = self;
   176→    }
   177→
   178→    /// Connect to an upstream server.
   179→    /// Performs DNS resolution, TCP connection, and optional TLS handshake.
   180→    /// Returns ConnectResult with timing information for observability.
   181→    /// TigerStyle S1: ~2 assertions, S3: bounded operations via Io.
   182→    pub fn connect(
   183→        self: *Client,
   184→        upstream: Upstream,
   185→        io: Io,
   186→    ) ClientError!ConnectResult {
   187→        // S1: preconditions
   188→        assert(upstream.host.len > 0); // S1: non-empty host
   189→        assert(upstream.port > 0); // S1: valid port
   190→
   191→        // Step 1: DNS resolution (timed)
   192→        const dns_start_ns = time.monotonicNanos();
   193→        const resolve_result = self.dns_resolver.resolve(
   194→            upstream.host,
   195→            upstream.port,
   196→            io,
   197→        ) catch {
   198→            return ClientError.DnsResolutionFailed;
   199→        };
   200→        const dns_end_ns = time.monotonicNanos();
   201→        const dns_duration_ns = time.elapsedNanos(dns_start_ns, dns_end_ns);
   202→
   203→        // S2: postcondition - resolved address has correct port
   204→        assert(resolve_result.address.getPort() == upstream.port);
   205→
   206→        // Step 2: TCP connection (timed)
   207→        const tcp_start_ns = time.monotonicNanos();
   208→        const fd = tcpConnect(resolve_result.address, io) catch |err| {
   209→            return mapConnectError(err);
   210→        };
   211→        const tcp_end_ns = time.monotonicNanos();
   212→        const tcp_connect_duration_ns = time.elapsedNanos(tcp_start_ns, tcp_end_ns);
   213→
   214→        // S2: postcondition - valid fd
   215→        assert(fd >= 0);
   216→
   217→        // Configure socket for low latency
   218→        _ = net.set_tcp_no_delay(fd);
   219→        _ = net.set_tcp_keep_alive(fd, 60, 10, 3);
   220→
   221→        // Get local port for observability
   222→        const local_port = getLocalPort(fd);
   223→
   224→        // Step 3: Optional TLS handshake (timed)
   225→        const tls_start_ns = time.monotonicNanos();
   226→        const socket: Socket = if (upstream.tls) blk: {
   227→            // TLS required - client_ctx must be set
   228→            const ctx = self.client_ctx orelse {
   229→                // No TLS context - cannot connect to TLS upstream
   230→                closeFd(fd);
   231→                return ClientError.TlsHandshakeFailed;
   232→            };
   233→
   234→            // Perform TLS handshake with SNI
   235→            // Strip trailing dot from hostname for SNI (FQDN dots are not valid in SNI)
   236→            const sni_host = if (std.mem.endsWith(u8, upstream.host, "."))
   237→                upstream.host[0 .. upstream.host.len - 1]
   238→            else
   239→                upstream.host;
   240→
   241→            const desired_alpn: ?[]const u8 = switch (upstream.http_protocol) {
   242→                .h1 => "http/1.1",
   243→                .h2 => "h2",
   244→                .h2c => null,
   245→            };
   246→
   247→            var tls_socket = Socket.TLS.TLSSocket.init_client(
   248→                fd,
   249→                ctx,
   250→                sni_host,
   251→                self.enable_ktls,
   252→                desired_alpn,
   253→            ) catch {
   254→                closeFd(fd);
   255→                return ClientError.TlsHandshakeFailed;
   256→            };
   257→
   258→            if (upstream.http_protocol == .h2) {
   259→                const negotiated = switch (tls_socket) {
   260→                    .tls => |tls_conn| tls_conn.stream.info.alpn(),
   261→                    .plain => null,
   262→                } orelse {
   263→                    tls_socket.close();
   264→                    return ClientError.TlsHandshakeFailed;
   265→                };
   266→                if (!std.mem.eql(u8, negotiated, "h2")) {
   267→                    tls_socket.close();
   268→                    return ClientError.TlsHandshakeFailed;
   269→                }
   270→            }
   271→
   272→            break :blk tls_socket;
   273→        } else blk: {
   274→            // Plaintext connection
   275→            break :blk Socket.Plain.init_client(fd);
   276→        };
   277→        const tls_end_ns = time.monotonicNanos();
   278→        const tls_handshake_duration_ns = if (upstream.tls)
   279→            time.elapsedNanos(tls_start_ns, tls_end_ns)
   280→        else
   281→            0;
   282→
   283→        // Build connection with timestamps
   284→        const now_ns = time.monotonicNanos();
   285→        const conn = Connection{
   286→            .socket = socket,
   287→            .created_ns = now_ns,
   288→            .last_used_ns = now_ns,
   289→        };
   290→
   291→        return ConnectResult{
   292→            .conn = conn,
   293→            .dns_duration_ns = dns_duration_ns,
   294→            .tcp_connect_duration_ns = tcp_connect_duration_ns,
   295→            .tls_handshake_duration_ns = tls_handshake_duration_ns,
   296→            .local_port = local_port,
   297→        };
   298→    }
   299→
   300→    /// Send an HTTP request on an existing connection.
   301→    /// Delegates to request.sendRequest with proper error mapping.
   302→    /// TigerStyle S1: Precondition assertions.
   303→    pub fn sendRequest(
   304→        self: *Client,
   305→        conn: *Connection,
   306→        req: *const types.Request,
   307→        effective_path: ?[]const u8,
   308→    ) ClientError!void {
   309→        _ = self; // Client state not needed for send
   310→
   311→        // S1: preconditions
   312→        const path = effective_path orelse req.path;
   313→        assert(path.len > 0); // S1: non-empty path
   314→
   315→        request_mod.sendRequest(&conn.socket, req, effective_path) catch |err| {
   316→            return mapRequestError(err);
   317→        };
   318→    }
   319→
   320→    /// Read HTTP response headers from an existing connection.
   321→    /// Delegates to response.readResponseHeaders with proper error mapping.
   322→    /// TigerStyle S1: Precondition assertions.
   323→    pub fn readResponseHeaders(
   324→        self: *Client,
   325→        conn: *Connection,
   326→        header_buf: []u8,
   327→    ) ClientError!ResponseHeaders {
   328→        _ = self; // Client state not needed for receive
   329→
   330→        // S1: preconditions
   331→        assert(header_buf.len > 0); // S1: non-empty buffer
   332→        assert(header_buf.len <= config.MAX_HEADER_SIZE_BYTES); // S1: bounded buffer
   333→
   334→        return response_mod.readResponseHeaders(&conn.socket, header_buf) catch |err| {
   335→            return mapResponseError(err);
   336→        };
   337→    }
   338→
   339→    /// Perform a complete HTTP request (connect + send + read headers).
   340→    /// Convenience function for simple request/response flows.
   341→    /// TigerStyle S1: Precondition assertions.
   342→    pub fn request(
   343→        self: *Client,
   344→        upstream: Upstream,
   345→        req: *const types.Request,
   346→        header_buf: []u8,
   347→        io: Io,
   348→    ) ClientError!RequestResult {
   349→        // S1: preconditions
   350→        assert(upstream.host.len > 0); // S1: non-empty host
   351→        assert(header_buf.len > 0); // S1: non-empty buffer
   352→
   353→        // Step 1: Connect
   354→        var connect_result = try self.connect(upstream, io);
   355→        errdefer connect_result.conn.close();
   356→
   357→        // Step 2: Send request
   358→        try self.sendRequest(&connect_result.conn, req, null);
   359→
   360→        // Step 3: Read response headers
   361→        const response = try self.readResponseHeaders(&connect_result.conn, header_buf);
   362→
   363→        // S2: postcondition - valid response status
   364→        assert(response.status >= 100 and response.status <= 599);
   365→
   366→        return .{
   367→            .conn = connect_result.conn,
   368→            .response = response,
   369→        };
   370→    }
   371→};
   372→
   373→// =============================================================================
   374→// Internal Functions
   375→// =============================================================================
   376→
   377→/// Get local port from connected socket.
   378→/// Returns 0 if unable to retrieve (non-fatal).
   379→/// TigerStyle: Graceful fallback, no panic on failure.
   380→fn getLocalPort(fd: i32) u16 {
   381→    assert(fd >= 0);
   382→
   383→    var addr: posix.sockaddr.in = std.mem.zeroes(posix.sockaddr.in);
   384→    var addr_len: posix.socklen_t = @sizeOf(posix.sockaddr.in);
   385→
   386→    if (std.c.getsockname(fd, @ptrCast(&addr), &addr_len) != 0) {
   387→        return 0;
   388→    }
   389→
   390→    return std.mem.bigToNative(u16, addr.port);
   391→}
   392→
   393→/// Perform TCP connection using Io async API.
   394→/// TigerStyle: Bounded via Io cancellation, explicit error return.
   395→fn tcpConnect(address: Io.net.IpAddress, io: Io) !i32 {
   396→    // Use IpAddress.connect() to perform async TCP connect
   397→    // This creates the socket and connects in one step
   398→    const stream = address.connect(io, .{ .mode = .stream }) catch {
   399→        return error.ConnectionFailed;
   400→    };
   401→
   402→    return stream.socket.handle;
   403→}
   404→
   405→/// Map TCP connect errors to ClientError.
   406→/// TigerStyle S6: Explicit error handling.
   407→fn mapConnectError(err: anyerror) ClientError {
   408→    return switch (err) {
   409→        error.ConnectionRefused => ClientError.TcpConnectFailed,
   410→        error.NetworkUnreachable => ClientError.TcpConnectFailed,
   411→        error.ConnectionFailed => ClientError.TcpConnectFailed,
   412→        error.ConnectionTimedOut => ClientError.TcpConnectTimeout,
   413→        error.ConnectionResetByPeer => ClientError.TcpConnectFailed,
   414→        else => ClientError.TcpConnectFailed,
   415→    };
   416→}
   417→
   418→/// Map request module errors to ClientError.
   419→/// TigerStyle S6: Explicit error handling.
   420→fn mapRequestError(err: request_mod.ClientError) ClientError {
   421→    return switch (err) {
   422→        request_mod.ClientError.SendFailed => ClientError.SendFailed,
   423→        request_mod.ClientError.SendTimeout => ClientError.SendTimeout,
   424→        request_mod.ClientError.BufferTooSmall => ClientError.BufferTooSmall,
   425→    };
   426→}
   427→
   428→/// Map response module errors to ClientError.
   429→/// TigerStyle S6: Explicit error handling.
   430→fn mapResponseError(err: ResponseError) ClientError {
   431→    return switch (err) {
   432→        ResponseError.RecvFailed => ClientError.RecvFailed,
   433→        ResponseError.RecvTimeout => ClientError.RecvTimeout,
   434→        ResponseError.ResponseHeadersTooLarge => ClientError.ResponseHeadersTooLarge,
   435→        ResponseError.InvalidResponseStatus => ClientError.InvalidResponseStatus,
   436→        ResponseError.InvalidResponseHeaders => ClientError.InvalidResponseHeaders,
   437→        ResponseError.ConnectionClosed => ClientError.ConnectionClosed,
   438→    };
   439→}
   440→
   441→// =============================================================================
   442→// Tests
   443→// =============================================================================
   444→
   445→test "Client.init creates client with valid fields" {
   446→    var dns_resolver: DnsResolver = undefined;
   447→    DnsResolver.init(&dns_resolver, .{});
   448→    const client = Client.init(
   449→        std.testing.allocator,
   450→        &dns_resolver,
   451→        null, // No TLS
   452→        false,
   453→    );
   454→
   455→    try std.testing.expect(@intFromPtr(client.dns_resolver) != 0);
   456→    try std.testing.expect(client.client_ctx == null);
   457→    try std.testing.expect(client.verify_tls == false);
   458→}
   459→
   460→test "Client.init with TLS context" {
   461→    var dns_resolver: DnsResolver = undefined;
   462→    DnsResolver.init(&dns_resolver, .{});
   463→
   464→    // We can't actually create a valid SSL_CTX in tests without OpenSSL setup,
   465→    // but we can verify the field is stored correctly with a dummy pointer.
   466→    // In real usage, the caller provides a properly initialized SSL_CTX.
   467→    const client = Client.init(
   468→        std.testing.allocator,
   469→        &dns_resolver,
   470→        null, // No TLS in test
   471→        true, // verify_tls enabled
   472→    );
   473→
   474→    try std.testing.expect(client.verify_tls == true);
   475→}
   476→
   477→test "Client.deinit is safe to call" {
   478→    var dns_resolver: DnsResolver = undefined;
   479→    DnsResolver.init(&dns_resolver, .{});
   480→    var client = Client.init(
   481→        std.testing.allocator,
   482→        &dns_resolver,
   483→        null,
   484→        false,
   485→    );
   486→
   487→    // Should not crash
   488→    client.deinit();
   489→}
   490→
   491→test "ClientError error set has all expected variants" {
   492→    // Verify all error variants exist
   493→    const errors = [_]ClientError{
   494→        ClientError.DnsResolutionFailed,
   495→        ClientError.TcpConnectFailed,
   496→        ClientError.TcpConnectTimeout,
   497→        ClientError.TlsHandshakeFailed,
   498→        ClientError.SendFailed,
   499→        ClientError.SendTimeout,
   500→        ClientError.BufferTooSmall,
   501→        ClientError.RecvFailed,
   502→        ClientError.RecvTimeout,
   503→        ClientError.ResponseHeadersTooLarge,
   504→        ClientError.InvalidResponseStatus,
   505→        ClientError.InvalidResponseHeaders,
   506→        ClientError.ConnectionClosed,
   507→    };
   508→
   509→    // Each error should be distinct
   510→    for (errors, 0..) |err1, i| {
   511→        for (errors[i + 1 ..]) |err2| {
   512→            try std.testing.expect(err1 != err2);
   513→        }
   514→    }
   515→}
   516→
   517→test "RequestResult struct layout" {
   518→    // Verify struct has expected fields
   519→    const info = @typeInfo(RequestResult);
   520→    try std.testing.expect(info == .@"struct");
   521→
   522→    const fields = info.@"struct".fields;
   523→    try std.testing.expectEqual(@as(usize, 2), fields.len);
   524→    try std.testing.expectEqualStrings("conn", fields[0].name);
   525→    try std.testing.expectEqualStrings("response", fields[1].name);
   526→}
   527→
   528→test "mapRequestError maps all variants" {
   529→    try std.testing.expectEqual(ClientError.SendFailed, mapRequestError(request_mod.ClientError.SendFailed));
   530→    try std.testing.expectEqual(ClientError.SendTimeout, mapRequestError(request_mod.ClientError.SendTimeout));
   531→    try std.testing.expectEqual(ClientError.BufferTooSmall, mapRequestError(request_mod.ClientError.BufferTooSmall));
   532→}
   533→
   534→test "mapResponseError maps all variants" {
   535→    try std.testing.expectEqual(ClientError.RecvFailed, mapResponseError(ResponseError.RecvFailed));
   536→    try std.testing.expectEqual(ClientError.RecvTimeout, mapResponseError(ResponseError.RecvTimeout));
   537→    try std.testing.expectEqual(ClientError.ResponseHeadersTooLarge, mapResponseError(ResponseError.ResponseHeadersTooLarge));
   538→    try std.testing.expectEqual(ClientError.InvalidResponseStatus, mapResponseError(ResponseError.InvalidResponseStatus));
   539→    try std.testing.expectEqual(ClientError.InvalidResponseHeaders, mapResponseError(ResponseError.InvalidResponseHeaders));
   540→    try std.testing.expectEqual(ClientError.ConnectionClosed, mapResponseError(ResponseError.ConnectionClosed));
   541→}
   542→
   543→test "mapConnectError maps common errors" {
   544→    try std.testing.expectEqual(ClientError.TcpConnectFailed, mapConnectError(error.ConnectionRefused));
   545→    try std.testing.expectEqual(ClientError.TcpConnectFailed, mapConnectError(error.NetworkUnreachable));
   546→    try std.testing.expectEqual(ClientError.TcpConnectFailed, mapConnectError(error.ConnectionFailed));
   547→    try std.testing.expectEqual(ClientError.TcpConnectTimeout, mapConnectError(error.ConnectionTimedOut));
   548→    try std.testing.expectEqual(ClientError.TcpConnectFailed, mapConnectError(error.ConnectionResetByPeer));
   549→    // Unknown errors map to TcpConnectFailed
   550→    try std.testing.expectEqual(ClientError.TcpConnectFailed, mapConnectError(error.OutOfMemory));
   551→}
