     2→//!
     3→//! Bounded parsing, encoding, and validation for SETTINGS payloads and
     4→//! connection-level peer configuration.
     5→//! TigerStyle: Fixed-capacity parsing, explicit validation, no allocation.
     6→
     7→const std = @import("std");
     8→const assert = std.debug.assert;
     9→
    10→const config = @import("serval-core").config;
    11→const frame = @import("frame.zig");
    12→
    13→pub const setting_size_bytes: u32 = 6;
    14→pub const default_header_table_size_bytes: u32 = 4096;
    15→pub const max_concurrent_streams_unbounded: u32 = std.math.maxInt(u32);
    16→pub const max_header_list_size_unbounded: u32 = std.math.maxInt(u32);
    17→pub const min_max_frame_size_bytes: u32 = 16_384;
    18→pub const max_max_frame_size_bytes: u32 = 16_777_215;
    19→
    20→pub const SettingId = enum(u16) {
    21→    header_table_size = 0x1,
    22→    enable_push = 0x2,
    23→    max_concurrent_streams = 0x3,
    24→    initial_window_size = 0x4,
    25→    max_frame_size = 0x5,
    26→    max_header_list_size = 0x6,
    27→    enable_connect_protocol = 0x8,
    28→};
    29→
    30→pub const Setting = struct {
    31→    id: u16,
    32→    value: u32,
    33→
    34→    pub fn knownId(self: Setting) ?SettingId {
    35→        return decodeSettingId(self.id);
    36→    }
    37→};
    38→
    39→pub const Settings = struct {
    40→    header_table_size_bytes: u32 = default_header_table_size_bytes,
    41→    enable_push: bool = true,
    42→    max_concurrent_streams: u32 = max_concurrent_streams_unbounded,
    43→    initial_window_size_bytes: u32 = config.H2_INITIAL_WINDOW_SIZE_BYTES,
    44→    max_frame_size_bytes: u32 = config.H2_MAX_FRAME_SIZE_BYTES,
    45→    max_header_list_size_bytes: u32 = max_header_list_size_unbounded,
    46→    enable_connect_protocol: bool = true,
    47→};
    48→
    49→pub const Error = error{
    50→    InvalidFrameType,
    51→    InvalidStreamId,
    52→    InvalidPayloadLength,
    53→    AckMustBeEmpty,
    54→    TooManySettings,
    55→    BufferTooSmall,
    56→    InvalidEnablePush,
    57→    InvalidInitialWindowSize,
    58→    InvalidMaxFrameSize,
    59→};
    60→
    61→pub fn validateFrame(header: frame.FrameHeader, payload: []const u8) Error!void {
    62→    assert(header.length == payload.len);
    63→    assert(header.frame_type == .settings);
    64→
    65→    if (header.stream_id != 0) return error.InvalidStreamId;
    66→    if ((header.flags & frame.flags_ack) != 0) {
    67→        if (payload.len != 0) return error.AckMustBeEmpty;
    68→        return;
    69→    }
    70→
    71→    if (!isPayloadLengthValid(payload.len)) return error.InvalidPayloadLength;
    72→    if (payload.len / setting_size_bytes > config.H2_MAX_SETTINGS_PER_FRAME) {
