diff --git a/serval-server/h1/server.zig b/serval-server/h1/server.zig
index 6fb7a45..bc54da1 100644
--- a/serval-server/h1/server.zig
+++ b/serval-server/h1/server.zig
@@ -91,10 +91,24 @@ const CONNECTION_READ_STALL_TIMEOUT_NS: u64 = 120 * time.ns_per_s;
 /// Explicit bound on WouldBlock retry attempts in plain-socket reads.
 const CONNECTION_READ_MAX_WOULDBLOCK_RETRIES: u32 = 240_000;

+
 /// Maximum attempts when taking TLS reload-control mutex.
 /// TigerStyle: Bounded spin loop for control-plane activation path.
 const TLS_RELOAD_CONTROL_LOCK_MAX_ATTEMPTS: u32 = 1_000_000;

+fn setConnectionNonBlocking(fd: i32) bool {
+    assert(fd >= 0);
+
+    const get_rc = std.posix.system.fcntl(fd, std.posix.F.GETFL, @as(usize, 0));
+    if (std.posix.errno(get_rc) != .SUCCESS) return false;
+
+    var flags: usize = @intCast(get_rc);
+    flags |= @as(usize, 1) << @bitOffsetOf(std.posix.O, "NONBLOCK");
+
+    const set_rc = std.posix.system.fcntl(fd, std.posix.F.SETFL, flags);
+    return std.posix.errno(set_rc) == .SUCCESS;
+}
+
 fn lockTlsReloadControlMutex(mutex: *std.atomic.Mutex) void {
     assert(@intFromPtr(mutex) != 0);

@@ -257,8 +271,9 @@ pub fn Server(
             listener_fd_out: ?*std.atomic.Value(i32),
         ) !void {
             assert(self.config.port > 0);
