    var connection_mutex: Io.Mutex = .init;

    try setConnectionNonBlocking(io_conn);
    log.debug("server: conn={d} h2 server driver start initial_bytes={d} settings_already_sent={}", .{
        connection_id,
        initial_bytes.len,
        options.local_settings_already_sent,
    });

