   154→    pub fn acquireOrConnect(
   155→        self: *UpstreamSessionPool,
   156→        client: *Client,
   157→        upstream: Upstream,
   158→        io: Io,
   159→    ) Error!AcquireResult {
   160→        assert(@intFromPtr(self) != 0);
   161→        assert(@intFromPtr(client) != 0);
   162→        assert(upstream.port > 0);
   163→
   164→        try validateUpstream(upstream);
   165→
   166→        const slot_index: usize = @intCast(upstream.idx);
   167→        assert(slot_index < slot_count);
   168→        var slot = &self.slots[slot_index];
   169→
   170→        if (slotHasAnySession(slot) and !slotMatchesUpstream(slot, upstream)) {
   171→            closeSlot(slot);
   172→        }
   173→
   174→        cleanupUnusableSessions(slot);
   175→        try rotateActiveSessionForRollover(slot);
   176→
   177→        if (slot.active_session) |*existing| {
   178→            if (sessionAcceptsNewStreams(existing)) {
   179→                existing.last_used_ns = time.monotonicNanos();
   180→                return .{
   181→                    .session = existing,
   182→                    .connect = .{
   183→                        .reused = true,
   184→                        .dns_duration_ns = 0,
   185→                        .tcp_connect_duration_ns = 0,
   186→                        .tls_handshake_duration_ns = 0,
   187→                        .local_port = 0,
   188→                    },
   189→                };
   190→            }
   191→        }
   192→
   193→        if (slot.draining_session) |*draining| {
   194→            if (!sessionHasActiveStreams(draining) or sessionNeedsReconnect(draining)) {
   195→                closeSession(&slot.draining_session);
   196→            }
   197→        }
   198→
   199→        if (slot.active_session == null and slot.draining_session != null and !sessionHasActiveStreams(&slot.draining_session.?)) {
   200→            closeSession(&slot.draining_session);
   201→        }
   202→
